package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        // Use DEFAULT CSVFormat instance for testing
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintCreatesCSVPrinter() throws Exception {
        File mockFile = mock(File.class);
        Charset charset = Charset.forName("UTF-8");

        // Mock CSVPrinter instance
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Use a spy on CSVFormat.DEFAULT but do not mock final method directly,
        // instead use a wrapper CSVFormat subclass with overridden print(File, Charset)
        CSVFormat spyFormat = new CSVFormatWrapper(csvFormat, mockPrinter);

        CSVPrinter printer = spyFormat.print(mockFile, charset);

        assertNotNull(printer);
        assertSame(mockPrinter, printer);
    }

    @Test
    void testPrintThrowsIOException() {
        Charset charset = Charset.forName("UTF-8");

        // Passing null file to cause NullPointerException and simulate error
        assertThrows(NullPointerException.class, () -> {
            csvFormat.print((File) null, charset);
        });
    }

    // Helper subclass to override print(File, Charset) without Mockito issues on final method
    private static class CSVFormatWrapper extends CSVFormat {
        private final CSVFormat delegate;
        private final CSVPrinter printerToReturn;

        CSVFormatWrapper(CSVFormat delegate, CSVPrinter printerToReturn) {
            super(delegate.getDelimiter(),
                  delegate.getQuoteCharacter(),
                  delegate.getQuoteMode(),
                  delegate.getCommentMarker(),
                  delegate.getEscapeCharacter(),
                  delegate.getIgnoreSurroundingSpaces(),
                  delegate.getIgnoreEmptyLines(),
                  delegate.getRecordSeparator(),
                  delegate.getNullString(),
                  null,
                  delegate.getHeader(),
                  delegate.getSkipHeaderRecord(),
                  delegate.getAllowMissingColumnNames(),
                  delegate.getIgnoreHeaderCase(),
                  delegate.getTrim(),
                  delegate.getTrailingDelimiter(),
                  delegate.getAutoFlush());
            this.delegate = delegate;
            this.printerToReturn = printerToReturn;
        }

        @Override
        public CSVPrinter print(final File out, final Charset charset) {
            return printerToReturn;
        }
    }
}
